{"code": "import urllib.request
import os

url = 'https://github.com/MetaCubeX/mihomo/releases/download/v1.19.26/mihomo-linux-arm64-v1.19.26.gz'
output = '/tmp/clash-new.gz'

# Download with retries
for attempt in range(3):
    try:
        print(f"Attempt {attempt + 1}/3...")
        req = urllib.request.Request(url, headers={'User-Agent': 'ClashMeta-Updater'})
        with urllib.request.urlopen(req, timeout=60) as r:
            with open(output, 'wb') as f:
                f.write(r.read())
        # Verify
        if os.path.exists(output) and os.path.getsize(output) > 1000000:  # >1MB
            print(f"✓ Downloaded {os.path.getsize(output)} bytes")
            break
    except Exception as e:
        print(f"Error: {e}")
        if attempt < 2:
            print("Retrying...")
        else:
            print("All attempts failed")

# Check file
if os.path.exists(output):
    import gzip
    try:
        with gzip.open(output, 'rb') as f:
            f.read(100)  # Test gzip
        print("✓ File is valid gzip")
    except Exception as e:
        print(f"Invalid gzip: {e}")
else:
    print("Download failed")"}

